import{_ as i,o as l,c as e,a3 as r}from"./chunks/framework.gsMzR_Kb.js";const p=JSON.parse('{"title":"学习方法","description":"以卦序学习并不冲突于专题整理，二者可以并行。","frontmatter":{"title":"学习方法","description":"以卦序学习并不冲突于专题整理，二者可以并行。"},"headers":[],"relativePath":"yijing/basics/learning-method.md","filePath":"yijing/basics/learning-method.md","lastUpdated":1777132262000}'),t={name:"yijing/basics/learning-method.md"};function o(h,a,n,d,s,c){return l(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="学习方法" tabindex="-1">学习方法 <a class="header-anchor" href="#学习方法" aria-label="Permalink to &quot;学习方法&quot;">​</a></h1><p>《易经》的学习如果一开始没有方法，很容易变成三种状态：</p><ul><li>记了很多术语，但没有整体感</li><li>看了很多讲解，但彼此口径混乱</li><li>抄了很多笔记，但后面很难再复用</li></ul><p>所以这里不主张“换一套新体系”，而是先把你已经在走的主线整理得更稳。</p><h2 id="一个适合长期走的三线结构" tabindex="-1">一个适合长期走的三线结构 <a class="header-anchor" href="#一个适合长期走的三线结构" aria-label="Permalink to &quot;一个适合长期走的三线结构&quot;">​</a></h2><p>你当前按卦序学习，这是很好的主线。</p><p>关键不是改掉它，而是给它加两条辅线，让阅读既不断线，也慢慢长出结构。</p><h2 id="主线-按卦序推进" tabindex="-1">主线：按卦序推进 <a class="header-anchor" href="#主线-按卦序推进" aria-label="Permalink to &quot;主线：按卦序推进&quot;">​</a></h2><ul><li>保持连续感</li><li>保持原典接触</li><li>保持长期节奏</li><li>每次只求把当前一卦读明白一点，不急着横扫全部</li></ul><h2 id="辅线一-概念专题化" tabindex="-1">辅线一：概念专题化 <a class="header-anchor" href="#辅线一-概念专题化" aria-label="Permalink to &quot;辅线一：概念专题化&quot;">​</a></h2><p>在学卦的同时，把反复出现的概念抽出来：</p><ul><li>阴阳</li><li>刚柔</li><li>中正</li><li>位</li><li>应</li><li>时</li><li>变易</li><li>象理用</li></ul><p>这样做的目的，不是把经文拆碎，而是避免每次遇到这些词都重新开始。</p><h2 id="辅线二-结构化记录" tabindex="-1">辅线二：结构化记录 <a class="header-anchor" href="#辅线二-结构化记录" aria-label="Permalink to &quot;辅线二：结构化记录&quot;">​</a></h2><p>每学一个卦，都至少留下一个小节点：</p><ul><li>卦名</li><li>卦象</li><li>核心句</li><li>经文里最难懂的一处</li><li>我的三问</li><li>可关联的专题</li></ul><p>这样做的好处是：</p><ul><li>不打断主线学习</li><li>又能逐步长出可搜索、可关联、可复用的知识网络</li></ul><h2 id="一页笔记最小模板" tabindex="-1">一页笔记最小模板 <a class="header-anchor" href="#一页笔记最小模板" aria-label="Permalink to &quot;一页笔记最小模板&quot;">​</a></h2><p>如果后续逐卦展开，建议每篇至少保留这些字段：</p><ol><li>这卦大体在说什么</li><li>卦辞与爻辞最先读哪几句</li><li>这一卦最突出的概念是什么</li><li>它和哪几个专题最相关</li><li>我目前读到哪一层</li></ol><p>这样做的好处是，后面无论补原典、补解读、补专题，都能接得上。</p><h2 id="初学时最值得避免的四个误区" tabindex="-1">初学时最值得避免的四个误区 <a class="header-anchor" href="#初学时最值得避免的四个误区" aria-label="Permalink to &quot;初学时最值得避免的四个误区&quot;">​</a></h2><h3 id="_1-把《易经》只当成占卜词典" tabindex="-1">1. 把《易经》只当成占卜词典 <a class="header-anchor" href="#_1-把《易经》只当成占卜词典" aria-label="Permalink to &quot;1. 把《易经》只当成占卜词典&quot;">​</a></h3><p>卦辞、爻辞当然会涉及吉凶，但《易经》的价值不只在“结果判断”，更在于它训练人看位置、看变化、看关系、看时机。</p><h3 id="_2-一开始就想把所有概念讲圆" tabindex="-1">2. 一开始就想把所有概念讲圆 <a class="header-anchor" href="#_2-一开始就想把所有概念讲圆" aria-label="Permalink to &quot;2. 一开始就想把所有概念讲圆&quot;">​</a></h3><p>很多概念要在多卦、多传、多次阅读中才慢慢稳定下来。先有工作定义，比一开始追求终极定义更重要。</p><h3 id="_3-只背结论-不看结构" tabindex="-1">3. 只背结论，不看结构 <a class="header-anchor" href="#_3-只背结论-不看结构" aria-label="Permalink to &quot;3. 只背结论，不看结构&quot;">​</a></h3><p>若只记“某卦是吉还是凶”，却不看上下卦、爻位、应比、时势，后面很难真正进入《易》的思维。</p><h3 id="_4-材料越看越多-自己的记录越少" tabindex="-1">4. 材料越看越多，自己的记录越少 <a class="header-anchor" href="#_4-材料越看越多-自己的记录越少" aria-label="Permalink to &quot;4. 材料越看越多，自己的记录越少&quot;">​</a></h3><p>别人的讲解是辅助，你自己的阅读痕迹才是后面继续深入的地基。</p><h2 id="一个可长期执行的节奏" tabindex="-1">一个可长期执行的节奏 <a class="header-anchor" href="#一个可长期执行的节奏" aria-label="Permalink to &quot;一个可长期执行的节奏&quot;">​</a></h2><ul><li>每次专注一卦或一个小概念</li><li>每周回看一次前面已读内容</li><li>每隔一段时间，把反复出现的词汇整理成专题页</li><li>不追求“全部看完”，而追求“越读越稳”</li></ul><h2 id="当前推荐阅读顺序" tabindex="-1">当前推荐阅读顺序 <a class="header-anchor" href="#当前推荐阅读顺序" aria-label="Permalink to &quot;当前推荐阅读顺序&quot;">​</a></h2><ol><li><a href="/Dao/yijing/basics/">基础入口</a></li><li><a href="/Dao/yijing/basics/core-concepts">核心概念</a></li><li><a href="/Dao/yijing/hexagrams/">六十四卦目录</a></li></ol>',35)])])}const b=i(t,[["render",o]]);export{p as __pageData,b as default};
